//==============================================================================
//  Constructor
//==============================================================================
diancm::diancm()
    : m_opMode(OpMode::None), m_startPtSpecified(false), m_endPtSpecified(false)
{
   try
   {
        diancm::theSession = Session::GetSession();
       diancm::theUI = UI::GetUI();

        // static 保证 dlxPath 在 DLL 生命周期内不析构，c_str() 指针持久有效
        static std::string dlxPath = ResolveDlxPath("diancm.dlx");
        theDlxFileName = dlxPath.c_str();
        theDialog = diancm::theUI->CreateDialog(theDlxFileName);

        theDialog->AddApplyHandler(make_callback(this, &diancm::apply_cb));
        theDialog->AddOkHandler(make_callback(this, &diancm::ok_cb));
        theDialog->AddUpdateHandler(make_callback(this, &diancm::update_cb));
        theDialog->AddInitializeHandler(make_callback(this, &diancm::initialize_cb));
        theDialog->AddDialogShownHandler(make_callback(this, &diancm::dialogShown_cb));
    }
    catch (const exception& ex)
    {
        throw;
    }
}

//==============================================================================
//  Destructor
//==============================================================================
diancm::~diancm()
{
    if (theDialog != nullptr)
    {
        delete theDialog;
        theDialog = nullptr;
    }
}

