//  GetEnumValue — safe enumeration value extraction
int diancm::GetEnumValue(NXOpen::BlockStyler::Enumeration* enumBlock)
{
    if (!enumBlock) return 0;
    PropertyList* props = enumBlock->GetProperties();
    return props ? props->GetEnum("Value") : 0;
}

//  UpdateStartPointUI — enable/disable start point enum based on selection count
void diancm::UpdateStartPointUI()
{
    if (!selection0 || !enum0 || !point0 || !toggle0) return;

    bool multiEnabled = toggle0->Value();

    // Try to switch SelectMode at runtime
    try
    {
        PropertyList* props = selection0->GetProperties();
        props->SetEnum("SelectMode", multiEnabled ? 1 : 0);
    }
    catch (...) { }

    if (multiEnabled)
    {
        int count = static_cast<int>(selection0->GetSelectedObjects().size());
        if (count >= 2)
        {
            enum0->SetEnable(false);
            m_startPtSpecified = true;
        }
        else
        {
            enum0->SetEnable(true);
        }
    }
    else
    {
        enum0->SetEnable(true);
        m_startPtSpecified = false;
    }
}
